mapper.select:
SELECT er.id, er.task_id AS taskId, et.task_name AS taskName, er.course_id AS courseId, mc.course_name AS courseName, er.total_score AS totalScore, er.comment_content AS commentContent, er.submit_time AS submitTime FROM eval_record er LEFT JOIN eval_task et ON et.id = er.task_id LEFT JOIN math_course mc ON mc.id = er.course_id
er.student_id = #{studentId}
AND er.task_id = #{taskId}
AND er.course_id = #{courseId}
ORDER BY er.submit_time DESC
